        except (json.JSONDecodeError, UnicodeDecodeError):
            pass

        # Fall back to pickle for backward compatibility
        # Note: This should only be used with trusted data
        preferences = pickle.loads(decoded_data)

        # Validate that the result is a dictionary
        if not isinstance(preferences, dict):
            return {}

        return preferences
    except (base64.binascii.Error, ValueError, pickle.UnpicklingError):
        # Return empty dict if decoding/parsing fails
        return {}

